            "-s".to_string(),
            sandbox_mode.to_string(),
            "-m".to_string(),
            model.to_string(),
            "-c".to_string(),
            format!("model_reasoning_effort=\"{reasoning_effort}\""),
            prompt,
        ],
    ))
